#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim) {
    int i, j, k;

    for (int offset = 0; offset < matrix_dim; offset += BLOCK_SIZE) {
        // Diagonal block factorization
        {
            float shadow[BLOCK_SIZE * BLOCK_SIZE];
            int tx;

            // Load diagonal block into shadow
            #pragma omp parallel for private(tx, i) shared(m, shadow, matrix_dim, offset)
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = (offset) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                    array_offset += matrix_dim;
                }
            }

            // Synchronize threads
            #pragma omp barrier

            for (i = 0; i < BLOCK_SIZE - 1; i++) {
                #pragma omp parallel for private(tx, j) shared(shadow, i)
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    if (tx > i) {
                        for (j = 0; j < i; j++)
                            shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                        shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
                    }
                }
                #pragma omp barrier

                #pragma omp parallel for private(tx, j) shared(shadow, i)
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    if (tx > i) {
                        for (j = 0; j < i + 1; j++)
                            shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
                    }
                }
                #pragma omp barrier
            }

            // Write back to global memory
            #pragma omp parallel for private(tx, i) shared(m, shadow, matrix_dim, offset)
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = (offset + 1) * matrix_dim + offset;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
                    array_offset += matrix_dim;
                }
            }
        }

        // Perimeter blocks update
        {
            float dia[BLOCK_SIZE * BLOCK_SIZE];
            float peri_row[BLOCK_SIZE * BLOCK_SIZE];
            float peri_col[BLOCK_SIZE * BLOCK_SIZE];
            int tx, i, j, idx;
            int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

            if (num_blocks > 0) {
                // Load dia, peri_row, peri_col
                #pragma omp parallel for private(tx, i, idx) shared(m, dia, peri_row, peri_col, matrix_dim, offset)
                for (tx = 0; tx < BLOCK_SIZE * 2; tx++) {
                    if (tx < BLOCK_SIZE) {
                        idx = tx;
                        int array_offset = offset * matrix_dim + offset;
                        for (i = 0; i < BLOCK_SIZE / 2; i++) {
                            dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }
                        array_offset = offset * matrix_dim + offset;
                        for (i = 0; i < BLOCK_SIZE; i++) {
                            peri_row[i * BLOCK_SIZE + idx] = m[array_offset + BLOCK_SIZE + idx];
                            array_offset += matrix_dim;
                        }
                    } else {
                        idx = tx - BLOCK_SIZE;
                        int array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
                        for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                            dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }
                        array_offset = (offset + BLOCK_SIZE) * matrix_dim + offset;
                        for (i = 0; i < BLOCK_SIZE; i++) {
                            peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }
                    }
                }

                // Update peri_row
                #pragma omp parallel for private(tx, i, j, idx) shared(peri_row, dia)
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    idx = tx;
                    for (i = 1; i < BLOCK_SIZE; i++) {
                        for (j = 0; j < i; j++)
                            peri_row[i * BLOCK_SIZE + idx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
                    }
                }

                // Update peri_col
                #pragma omp parallel for private(tx, i, j, idx) shared(peri_col, dia)
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    idx = tx;
                    for (i = 0; i < BLOCK_SIZE; i++) {
                        for (j = 0; j < i; j++)
                            peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                        peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
                    }
                }

                // Write back peri_row and peri_col to m
                #pragma omp parallel for private(tx, i) shared(m, peri_row, peri_col, matrix_dim, offset)
                for (tx = 0; tx < BLOCK_SIZE * 2; tx++) {
                    if (tx < BLOCK_SIZE) {
                        idx = tx;
                        int array_offset = (offset + 1) * matrix_dim + offset;
                        for (i = 1; i < BLOCK_SIZE; i++) {
                            m[array_offset + BLOCK_SIZE + idx] = peri_row[i * BLOCK_SIZE + idx];
                            array_offset += matrix_dim;
                        }
                    } else {
                        idx = tx - BLOCK_SIZE;
                        int array_offset = (offset + BLOCK_SIZE) * matrix_dim + offset;
                        for (i = 0; i < BLOCK_SIZE; i++) {
                            m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
                            array_offset += matrix_dim;
                        }
                    }
                }
            }
        }

        // Internal blocks update
        {
            int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
            if (num_blocks > 0) {
                float *peri_row = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
                float *peri_col = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
                if (!peri_row || !peri_col) {
                    fprintf(stderr, "Failed to allocate peri_row or peri_col\n");
                    free(peri_row);
                    free(peri_col);
                    return;
                }

                for (int by = 0; by < num_blocks; by++) {
                    for (int bx = 0; bx < num_blocks; bx++) {
                        // Load peri_row and peri_col
                        #pragma omp parallel for collapse(2) private(i, j) shared(m, peri_row, peri_col, matrix_dim, offset, bx, by)
                        for (i = 0; i < BLOCK_SIZE; i++) {
                            for (j = 0; j < BLOCK_SIZE; j++) {
                                peri_row[i * BLOCK_SIZE + j] = m[(offset + i) * matrix_dim + offset + BLOCK_SIZE * (bx + 1) + j];
                                peri_col[i * BLOCK_SIZE + j] = m[(offset + BLOCK_SIZE * (by + 1) + i) * matrix_dim + offset + j];
                            }
                        }

                        // Compute internal block update
                        #pragma omp parallel for collapse(2) private(i, j, k) shared(m, peri_row, peri_col, matrix_dim, offset, bx, by)
                        for (i = 0; i < BLOCK_SIZE; i++) {
                            for (j = 0; j < BLOCK_SIZE; j++) {
                                float sum = 0.0f;
                                for (k = 0; k < BLOCK_SIZE; k++) {
                                    sum += peri_col[i * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + j];
                                }
                                m[(offset + BLOCK_SIZE * (by + 1) + i) * matrix_dim + offset + BLOCK_SIZE * (bx + 1) + j] -= sum;
                            }
                        }
                    }
                }
                free(peri_row);
                free(peri_col);
            }
        }
    }
}
